#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[1005]; scanf("%s", s);
        int cnt[26] = {0};
        for(int i=0;i<N;i++) cnt[s[i]-'a']++;
        int ok = 1;
        for(int i=0;i<26;i++) if(cnt[i]%2){ ok = 0; break; }
        printf(ok?"YES\n":"NO\n");
    }
    return 0;
}

