let idx = 0;
const T = Number(input[idx++]);
let res = [];
for(let t=0; t<T; t++){
  const N = Number(input[idx++]);
  const s = input[idx++];
  const cnt = new Array(26).fill(0);
  for(let i=0;i<N;i++) cnt[s.charCodeAt(i)-97]++;
